CREATE TABLE "public"."users"("id" bigserial NOT NULL, "username" bpchar NOT NULL, "email" character NOT NULL, "phone" character NOT NULL, "password" character NOT NULL, "status" int2 NOT NULL, "secret_token" character NOT NULL, "created_at" timestamptz NOT NULL DEFAULT now(), "updated_at" timestamptz NOT NULL DEFAULT now(), "last_seen_at" timestamptz NOT NULL DEFAULT now(), PRIMARY KEY ("id") , UNIQUE ("username"), UNIQUE ("email"), UNIQUE ("phone"), UNIQUE ("secret_token"));
